SELECT NOTC.SUBJECT , NOTC.NOTICE_NUM , NOTC.NOTICE_TEXT_NUM , NOTC.VIEW_TYPE , (NOTC.VIEW_CNT, 0) AS VIEW_CNT , NOTC.REG_USER_ID , UR.USER_NM AS REG_USER_NAME , NOTC.ATT_FILE_NUM FROM STOCNOTC NOTC LEFT JOIN STOCUSER UR ON (NOTC.GATE_CD = UR.GATE_CD AND NOTC.REG_USER_ID = UR.USER_ID) WHERE NOTC.GATE_CD = #{ses.gateCd} AND NOTC.NOTICE_NUM = #{NOTICE_NUM}
AND TO_CHAR(NOTC.START_DATE, 'yyyyMMdd') <= TO_CHAR(SYSDATE, 'yyyyMMdd') AND TO_CHAR(NOTC.END_DATE, 'yyyyMMdd') >= TO_CHAR(SYSDATE, 'yyyyMMdd')
AND CONVERT(CHAR(8), NOTC.START_DATE , 112) <= CONVERT(CHAR(8), SYSDATE , 112) AND CONVERT(CHAR(8), NOTC.END_DATE , 112) >= CONVERT(CHAR(8), SYSDATE , 112)
